"""Validate new pipeline (L1→L2→L3→L4) against MATLAB reference data.

Compares the scor160-based pipeline output against *_validation.nc and
*_scalar_spectra.nc files generated by MATLAB/ODAS.

Unlike test_matlab_epsilon.py (which uses the old get_diss path), this
exercises the full pipeline: pfile_to_l1data → process_l2 → process_l3
→ process_l4 for epsilon, and process_l2_chi → process_l3_chi for scalar
spectra.
"""

import os
from pathlib import Path

import numpy as np
import pytest

netCDF4 = pytest.importorskip("netCDF4")

pytestmark = pytest.mark.matlab

VMP_DIR = Path(__file__).parents[1] / "VMP"

# ---------------------------------------------------------------------------
# File discovery — same pattern as test_matlab_epsilon.py
# MAX_MATLAB_FILES controls how many files to test (default 12, 0 = all).
# ---------------------------------------------------------------------------

_val_files = sorted(VMP_DIR.glob("*_validation.nc")) if VMP_DIR.exists() else []
_scalar_files = sorted(VMP_DIR.glob("*_scalar_spectra.nc")) if VMP_DIR.exists() else []
_max = int(os.environ.get("MAX_MATLAB_FILES", "12"))
if _max and len(_val_files) > _max:
    _step = len(_val_files) / _max
    _val_files = [_val_files[int(i * _step)] for i in range(_max)]
if _max and len(_scalar_files) > _max:
    _step = len(_scalar_files) / _max
    _scalar_files = [_scalar_files[int(i * _step)] for i in range(_max)]


def _file_id(path):
    stem = path.stem.replace("_validation", "").replace("_scalar_spectra", "")
    return stem.split("_")[-1]


# ---------------------------------------------------------------------------
# Session-scoped caches for expensive pipeline runs
# ---------------------------------------------------------------------------

_eps_cache = {}
_chi_cache = {}


def _cached_pipeline_epsilon(p_path, val):
    key = Path(p_path).resolve()
    if key not in _eps_cache:
        _eps_cache[key] = _run_pipeline_epsilon(p_path, val)
    return _eps_cache[key]


def _cached_pipeline_chi(p_path, val):
    key = Path(p_path).resolve()
    if key not in _chi_cache:
        _chi_cache[key] = _run_pipeline_chi(p_path, val)
    return _chi_cache[key]


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------


def _load_validation(nc_path: Path) -> dict:
    """Load a *_validation.nc file into a dict."""
    out = {}
    with netCDF4.Dataset(str(nc_path), "r") as ds:
        for attr in ds.ncattrs():
            out[attr] = ds.getncattr(attr)
        for vname in ds.variables:
            out[vname] = np.squeeze(ds.variables[vname][:])

        n_profiles = int(out["n_profiles"])
        keys = [
            "eps_all",
            "K_max_all",
            "FM_all",
            "mad_all",
            "method_all",
            "nu_all",
            "speed_all",
            "P_mean_all",
            "T_mean_all",
            "t_mean_all",
            "K_all",
            "F_all",
            "spec_sh_all",
        ]
        for k in keys:
            out[k] = [None] * n_profiles
        for pi in range(n_profiles):
            grp = ds.groups.get(f"profile_{pi + 1:03d}")
            if grp is None:
                continue
            out["eps_all"][pi] = np.squeeze(grp.variables["epsilon"][:])
            out["K_max_all"][pi] = np.squeeze(grp.variables["K_max"][:])
            out["FM_all"][pi] = np.squeeze(grp.variables["FM"][:])
            out["mad_all"][pi] = np.squeeze(grp.variables["mad"][:])
            out["method_all"][pi] = np.squeeze(grp.variables["method"][:])
            out["nu_all"][pi] = np.squeeze(grp.variables["nu"][:])
            out["speed_all"][pi] = np.squeeze(grp.variables["speed"][:])
            out["P_mean_all"][pi] = np.squeeze(grp.variables["P_mean"][:])
            out["T_mean_all"][pi] = np.squeeze(grp.variables["T_mean"][:])
            out["t_mean_all"][pi] = np.squeeze(grp.variables["t_mean"][:])
            out["K_all"][pi] = np.squeeze(grp.variables["K"][:])
            out["F_all"][pi] = np.squeeze(grp.variables["F"][:])
            if "spec_shear_clean" in grp.variables:
                out["spec_sh_all"][pi] = np.squeeze(grp.variables["spec_shear_clean"][:])
    return out


def _load_scalar_validation(nc_path: Path) -> dict:
    """Load a *_scalar_spectra.nc file into a dict."""
    out = {}
    with netCDF4.Dataset(str(nc_path), "r") as ds:
        for attr in ds.ncattrs():
            out[attr] = ds.getncattr(attr)
        for vname in ds.variables:
            out[vname] = np.squeeze(ds.variables[vname][:])

        n_profiles = int(out["n_profiles"])
        keys = [
            "scalar_spec_all",
            "K_scalar_all",
            "F_scalar_all",
            "speed_scalar_all",
            "P_scalar_all",
            "t_scalar_all",
        ]
        for k in keys:
            out[k] = [None] * n_profiles
        for pi in range(n_profiles):
            grp = ds.groups.get(f"profile_{pi + 1:03d}")
            if grp is None:
                continue
            out["scalar_spec_all"][pi] = np.squeeze(grp.variables["scalar_spec"][:])
            out["K_scalar_all"][pi] = np.squeeze(grp.variables["K"][:])
            out["F_scalar_all"][pi] = np.squeeze(grp.variables["F"][:])
            out["speed_scalar_all"][pi] = np.squeeze(grp.variables["speed"][:])
            out["P_scalar_all"][pi] = np.squeeze(grp.variables["P_mean"][:])
            out["t_scalar_all"][pi] = np.squeeze(grp.variables["t_mean"][:])
    return out


def _run_pipeline_epsilon(p_path, val):
    """Run the new pipeline L1→L2→L3→L4 for epsilon on each profile."""
    from odas_tpw.rsi.adapter import pfile_to_l1data
    from odas_tpw.rsi.p_file import PFile
    from odas_tpw.rsi.profile import _smooth_fall_rate, get_profiles
    from odas_tpw.scor160.io import L2Params, L3Params
    from odas_tpw.scor160.l2 import process_l2
    from odas_tpw.scor160.l3 import process_l3
    from odas_tpw.scor160.l4 import process_l4

    fft_length = int(val["fft_length"])
    diss_length = int(val["diss_length"])
    overlap = int(val["overlap"])
    HP_cut = float(val.get("HP_cut", 0.25))
    f_AA = float(val["f_AA"])
    fit_order = int(val["fit_order"])
    P_min = float(val["P_min"])
    W_min = float(val["W_min"])
    min_duration = float(val["min_duration"])

    pf = PFile(p_path)
    P_slow = pf.channels.get("P_dP", pf.channels.get("P"))
    W_slow = _smooth_fall_rate(P_slow, pf.fs_slow)
    profiles = get_profiles(
        P_slow,
        W_slow,
        pf.fs_slow,
        P_min=P_min,
        W_min=W_min,
        min_duration=min_duration,
    )

    results = []
    for s_slow, e_slow in profiles:
        l1 = pfile_to_l1data(pf, profile_slice=(s_slow, e_slow))

        l2_params = L2Params(
            HP_cut=HP_cut,
            despike_sh=np.array([8.0, 0.5, 0.04]),
            despike_A=np.array([np.inf, 0.5, 0.04]),
            profile_min_W=W_min,
            profile_min_P=P_min,
            profile_min_duration=min_duration,
            speed_tau=1.5,
        )
        l2 = process_l2(l1, l2_params)

        l3_params = L3Params(
            fft_length=fft_length,
            diss_length=diss_length,
            overlap=overlap,
            HP_cut=HP_cut,
            fs_fast=l1.fs_fast,
            goodman=True,
        )
        l3 = process_l3(l2, l1, l3_params)
        if l3.n_spectra == 0:
            continue

        l4 = process_l4(l3, temp=l3.temp, f_AA=f_AA, fit_order=fit_order)
        results.append(l4)

    return results, profiles


def _run_pipeline_chi(p_path, val):
    """Run the new pipeline L1→L2→L2chi→L3chi for scalar spectra."""
    from odas_tpw.chi.l2_chi import L2ChiParams, process_l2_chi
    from odas_tpw.chi.l3_chi import process_l3_chi
    from odas_tpw.rsi.adapter import pfile_to_l1data
    from odas_tpw.rsi.p_file import PFile
    from odas_tpw.rsi.profile import _smooth_fall_rate, get_profiles
    from odas_tpw.scor160.io import L2Params, L3Params
    from odas_tpw.scor160.l2 import process_l2

    fft_length = int(val["fft_length"])
    spec_length = int(val["spec_length"])
    overlap = int(val["overlap"])
    HP_cut = float(val.get("HP_cut", 0.25))

    pf = PFile(p_path)
    P_slow = pf.channels.get("P_dP", pf.channels.get("P"))
    W_slow = _smooth_fall_rate(P_slow, pf.fs_slow)
    profiles = get_profiles(
        P_slow,
        W_slow,
        pf.fs_slow,
        P_min=0.5,
        W_min=0.3,
        min_duration=7.0,
    )

    results = []
    for s_slow, e_slow in profiles:
        l1 = pfile_to_l1data(pf, profile_slice=(s_slow, e_slow))

        l2_params = L2Params(
            HP_cut=HP_cut,
            despike_sh=np.array([8.0, 0.5, 0.04]),
            despike_A=np.array([np.inf, 0.5, 0.04]),
            profile_min_W=0.3,
            profile_min_P=0.5,
            profile_min_duration=7.0,
            speed_tau=1.5,
        )
        l2 = process_l2(l1, l2_params)

        l2_chi_params = L2ChiParams(HP_cut=HP_cut)
        l2_chi = process_l2_chi(l1, l2, l2_chi_params)

        l3_chi_params = L3Params(
            fft_length=fft_length,
            diss_length=spec_length,
            overlap=overlap,
            HP_cut=HP_cut,
            fs_fast=l1.fs_fast,
            goodman=True,
        )

        l3_chi = process_l3_chi(l2_chi, l3_chi_params)
        if l3_chi.n_spectra > 0:
            results.append(l3_chi)

    return results, profiles


def _match_profiles_by_time(py_times, ml_times, max_diff=60.0):
    """Match profiles by first-estimate time. Returns (py_idx, ml_idx) pairs."""
    matched = []
    used_ml = set()
    for pi, py_t in enumerate(py_times):
        if np.isnan(py_t):
            continue
        best_mi = None
        best_diff = np.inf
        for mi, ml_t in enumerate(ml_times):
            if mi in used_ml or np.isnan(ml_t):
                continue
            diff = abs(py_t - ml_t)
            if diff < best_diff:
                best_diff = diff
                best_mi = mi
        if best_mi is not None and best_diff < max_diff:
            matched.append((pi, best_mi))
            used_ml.add(best_mi)
    return matched


def _ml_first_times(val, time_key, n_key="n_profiles"):
    """Extract first-estimate time per MATLAB profile."""
    times = []
    for i in range(int(val[n_key])):
        t = np.atleast_1d(val[time_key][i])
        valid = t[np.isfinite(t)]
        times.append(valid[0] if len(valid) > 0 else np.nan)
    return times


