@pytest.fixture(scope="module", params=_val_files, ids=[_file_id(p) for p in _val_files])
def eps_validation_pair(request):
    """Yield (p_path, validation_dict) for each file with validation data."""
    val_path = request.param
    stem = val_path.stem.replace("_validation", "")
    p_path = val_path.with_name(stem + ".p")
    if not p_path.exists():
        pytest.skip(f"No .p file for {val_path.name}")
    return p_path, _load_validation(val_path)


@pytest.fixture(scope="module")
def epsilon_results(eps_validation_pair):
    """Run pipeline for epsilon and match against MATLAB. Cached per file."""
    p_path, val = eps_validation_pair
    l4_list, _profiles = _cached_pipeline_epsilon(p_path, val)

    py_times = [l4.time[0] if l4.n_spectra > 0 else np.nan for l4 in l4_list]
    ml_times = _ml_first_times(val, "t_mean_all")
    matched = _match_profiles_by_time(py_times, ml_times)
    return l4_list, val, matched


