class TestPipelineChiSpectraVsMatlab:
    """Compare new pipeline scalar spectra against MATLAB get_scalar_spectra_odas."""

    def test_profile_count(self, chi_results):
        l3_chi_list, val, _matched = chi_results
        ml_n = int(val["n_profiles"])
        py_n = len(l3_chi_list)
        assert abs(py_n - ml_n) <= 3, f"Profile count: Python {py_n} vs MATLAB {ml_n}"

    def test_most_profiles_matched(self, chi_results):
        l3_chi_list, val, matched = chi_results
        ml_n = int(val["n_profiles"])
        py_n = len(l3_chi_list)
        min_total = min(ml_n, py_n)
        if min_total >= 3:
            assert len(matched) >= min_total * 0.7

    def test_estimate_count(self, chi_results):
        """Number of spectral windows should be close."""
        l3_chi_list, val, matched = chi_results
        for pi, mi in matched:
            l3 = l3_chi_list[pi]
            py_n = l3.n_spectra
            ml_spec = np.atleast_3d(val["scalar_spec_all"][mi])
            ml_n = ml_spec.shape[0]
            ratio = py_n / ml_n if ml_n > 0 else 0
            assert 0.8 < ratio < 1.2, f"Profile {mi}: estimate count Python {py_n} vs MATLAB {ml_n}"

    def test_scalar_spectra_log_agreement(self, chi_results):
        """Temperature gradient spectra should agree in log-space."""
        l3_chi_list, val, matched = chi_results

        for pi, mi in matched:
            l3 = l3_chi_list[pi]
            py_spec = l3.gradt_spec
            ml_spec = val["scalar_spec_all"][mi]
            ml_spec = np.atleast_3d(ml_spec)
            ml_spec = np.transpose(ml_spec, (1, 2, 0))

            n_probe = min(py_spec.shape[0], ml_spec.shape[0])
            n_est = min(py_spec.shape[2], ml_spec.shape[2])
            n_freq = min(py_spec.shape[1], ml_spec.shape[1])

            if n_est < 3:
                continue

            for ci in range(n_probe):
                log_diffs = []
                for j in range(n_est):
                    py_s = py_spec[ci, 1:n_freq, j]
                    ml_s = ml_spec[ci, 1:n_freq, j]
                    valid = np.isfinite(py_s) & np.isfinite(ml_s) & (py_s > 0) & (ml_s > 0)
                    if np.sum(valid) < 5:
                        continue
                    log_diff = np.abs(np.log10(py_s[valid]) - np.log10(ml_s[valid]))
                    log_diffs.extend(log_diff.tolist())

                if len(log_diffs) > 10:
                    median_diff = np.median(log_diffs)
                    assert median_diff < 0.5, (
                        f"Profile {mi}, therm {ci}: median log10 spec diff {median_diff:.3f}"
                    )

    def test_speed_consistency(self, chi_results):
        """Per-window speed should match."""
        l3_chi_list, val, matched = chi_results

        for pi, mi in matched:
            l3 = l3_chi_list[pi]
            py_spd = l3.pspd_rel
            ml_spd = np.atleast_1d(val["speed_scalar_all"][mi])
            n = min(len(py_spd), len(ml_spd))
            if n < 5:
                continue
            valid = (
                np.isfinite(py_spd[:n])
                & np.isfinite(ml_spd[:n])
                & (py_spd[:n] > 0.1)
                & (ml_spd[:n] > 0.1)
            )
            if np.sum(valid) < 5:
                continue
            corr = np.corrcoef(py_spd[:n][valid], ml_spd[:n][valid])[0, 1]
            assert corr > 0.75, f"Profile {mi}: speed corr {corr:.3f}"

    def test_wavenumber_vectors(self, chi_results):
        """K vectors should match (K = F/W)."""
        l3_chi_list, val, matched = chi_results

        for pi, mi in matched:
            l3 = l3_chi_list[pi]
            py_K = l3.kcyc
            ml_K = np.atleast_2d(val["K_scalar_all"][mi])
            if ml_K.shape[0] != py_K.shape[0]:
                ml_K = ml_K.T

            n_est = min(py_K.shape[1], ml_K.shape[1])
            n_freq = min(py_K.shape[0], ml_K.shape[0])

            for j in range(min(n_est, 5)):
                py_k = py_K[:n_freq, j]
                ml_k = ml_K[:n_freq, j]
                valid = np.isfinite(py_k) & np.isfinite(ml_k) & (py_k > 0) & (ml_k > 0)
                if np.sum(valid) < 3:
                    continue
                # K = F/speed, so K tolerance must accommodate speed differences
                np.testing.assert_allclose(
                    py_k[valid],
                    ml_k[valid],
                    rtol=0.15,
                    err_msg=f"Profile {mi}, est {j}: K mismatch",
                )

    def test_pressure_range(self, chi_results):
        """Pressure ranges should match."""
        l3_chi_list, val, matched = chi_results

        for pi, mi in matched:
            l3 = l3_chi_list[pi]
            py_P = l3.pres
            ml_P = np.atleast_1d(val["P_scalar_all"][mi])
            py_max = np.nanmax(py_P)
            ml_max = np.nanmax(ml_P)
            if ml_max > 10:
                ratio = py_max / ml_max
                assert 0.7 < ratio < 1.3, f"Profile {mi}: max P ratio {ratio:.2f}"
